+  const catalogResult = readJsonFile(catalogPath, 'catalog_read_failed');
+  if (catalogResult.error) {
+    writeCartError(catalogResult.error);
+    return;
+  }
+
+  const catalog = catalogResult.value;
+  for (const item of cart.items) {
