const { test } = require('node:test');
const assert = require('node:assert');
const { execFileSync, spawnSync } = require('node:child_process');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');

const CLI = path.join(__dirname, '..', 'bin', 'cli.js');

function run(args) {
  return execFileSync('node', [CLI, ...args], { encoding: 'utf8' });
}

function runResult(args) {
  return spawnSync('node', [CLI, ...args], { encoding: 'utf8' });
}

function withCart(cart, callback) {
  const directory = fs.mkdtempSync(path.join(os.tmpdir(), 'bench-cli-cart-'));
  const inputPath = path.join(directory, 'cart.json');
  fs.writeFileSync(inputPath, JSON.stringify(cart));

  try {
    return callback(inputPath);
  } finally {
    fs.rmSync(directory, { recursive: true, force: true });
  }
}

test('hello default', () => {
  const out = run(['hello']);
  assert.match(out, /Hello, world!/);
});

test('hello with --name', () => {
  const out = run(['hello', '--name', 'alice']);
  assert.match(out, /Hello, alice!/);
});

test('version prints package version', () => {
  const out = run(['version']);
  assert.match(out, /\d+\.\d+\.\d+/);
});

test('cart combines items and applies promotions, coupon, tax, and shipping', () => {
  withCart({
    state: 'CA',
    coupon: 'ORDER10',
    items: [
      { sku: 'TEE', qty: 2 },
      { sku: 'MUG', qty: 1 },
      { sku: 'TEE', qty: 1 },
      { sku: 'BAG', qty: 2 },
    ],
  }, (inputPath) => {
    const result = runResult(['cart', '--input', inputPath]);
    const expected = {
      subtotal_cents: 15100,
      line_discount_cents: 3500,
      coupon_discount_cents: 1160,
      tax_cents: 858,
      shipping_cents: 0,
      total_cents: 11298,
      items: [
        {
          sku: 'TEE',
          qty: 3,
          line_subtotal_cents: 7500,
          line_discount_cents: 2500,
          line_total_cents: 5000,
        },
        {
          sku: 'MUG',
          qty: 1,
          line_subtotal_cents: 1200,
          line_discount_cents: 0,
          line_total_cents: 1200,
        },
        {
          sku: 'BAG',
          qty: 2,
          line_subtotal_cents: 6400,
          line_discount_cents: 1000,
          line_total_cents: 5400,
        },
      ],
    };

    assert.strictEqual(result.status, 0);
    assert.strictEqual(result.stderr, '');
    assert.strictEqual(result.stdout, `${JSON.stringify(expected)}\n`);
  });
});

test('cart rejects a combined quantity above stock', () => {
  withCart({
    state: 'CA',
    coupon: null,
    items: [
      { sku: 'BAG', qty: 3 },
      { sku: 'BAG', qty: 2 },
    ],
  }, (inputPath) => {
    const result = runResult(['cart', '--input', inputPath]);

    assert.strictEqual(result.status, 2);
    assert.strictEqual(result.stdout, '');
    assert.strictEqual(
      result.stderr,
      '{"error":"invalid_stock","sku":"BAG","available":4,"requested":5}\n',
    );
  });
});
